+
+  os::PlaceholderRegion region = os::reserve_placeholder_memory(size, mtTest);
+  ASSERT_FALSE(region.is_empty());
+  ASSERT_EQ(region.size(), size);
+  ASSERT_NE(region.base(), (char*)nullptr);
+
+  os::release_placeholder_memory(region);
+}
+

